class ModelNew(nn.Module):
    """
    Optimized model with fused Conv2D + Mish + Mish CUDA kernel.
    """
    def __init__(self, in_channels, out_channels, kernel_size):
        super(ModelNew, self).__init__()
        self.in_channels = in_channels
        self.out_channels = out_channels
        self.kernel_size = kernel_size if isinstance(kernel_size, tuple) else (kernel_size, kernel_size)

        # Initialize weights and bias
        self.weight = nn.Parameter(torch.empty(out_channels, in_channels, 
                                               self.kernel_size[0], self.kernel_size[1]))
        self.bias = nn.Parameter(torch.empty(out_channels))

        # Initialize parameters
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        if self.bias is not None:
            fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
            bound = 1 / math.sqrt(fan_in)
            nn.init.uniform_(self.bias, -bound, bound)

        # Convolution parameters - match PyTorch's default Conv2d
        self.stride = (1, 1)
        self.padding = (0, 0)  # No padding to match original model
        self.dilation = (1, 1)

        # Load custom CUDA kernel
        self.fused_conv_mish = fused_conv_mish

    def forward(self, x):
        # Use fused CUDA kernel for Conv2D + Mish - Mish
        return self.fused_conv_mish.fused_conv_mish_cuda(
            x,
            self.weight,
            self.bias,
            self.stride[0],
            self.stride[1],
            self.padding[0],
            self.padding[1],
            self.dilation[0],
            self.dilation[1]
        )

