fused_conv_mish_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <math.h>

// Mish activation function: x * tanh(softplus(x))
__device__ __forceinline__ float mish_func(float x) {
    float sp = log1pf(expf(x));
    float tanh_sp = tanhf(sp);
    return x * tanh_sp;
}

// Fused kernel for Conv2D + Mish + Mish
template<typename scalar_t>
__global__ void fused_conv_mish_kernel(
    const scalar_t* input,
    const scalar_t* weight,
    const scalar_t* bias,
    scalar_t* output,
    const int batch_size,
    const int in_channels,
    const int out_channels,
    const int height,
    const int width,
    const int kernel_h,
    const int kernel_w,
    const int pad_h,
    const int pad_w,
    const int stride_h,
    const int stride_w,
    const int dilation_h,
    const int dilation_w,
    const int out_height,
    const int out_width) {

    // Calculate output position
    const int n = blockIdx.z;  // batch index
    const int oc = blockIdx.y; // output channel
    const int oh = blockIdx.x * blockDim.y + threadIdx.y; // output height
    const int ow = threadIdx.x; // output width

    if (n >= batch_size || oc >= out_channels || oh >= out_height || ow >= out_width) {
        return;
    }

    scalar_t result = bias ? bias[oc] : static_cast<scalar_t>(0);

    // Perform convolution
    for (int ic = 0; ic < in_channels; ++ic) {
        for (int kh = 0; kh < kernel_h; ++kh) {
            for (int kw = 0; kw < kernel_w; ++kw) {
                int ih = oh * stride_h - pad_h + kh * dilation_h;
                int iw = ow * stride_w - pad_w + kw * dilation_w;

                if (ih >= 0 && ih < height && iw >= 0 && iw < width) {
                    int input_idx = ((n * in_channels + ic) * height + ih) * width + iw;
                    int weight_idx = ((oc * in_channels + ic) * kernel_h + kh) * kernel_w + kw;

                    result += input[input_idx] * weight[weight_idx];
                }
            }
        }
    }

    // Apply Mish activation twice
    float result_float = result;
    result_float = mish_func(result_float);
    result_float = mish_func(result_float);

    // Store result
    int output_idx = ((n * out_channels + oc) * out_height + oh) * out_width + ow;
    output[output_idx] = static_cast<scalar_t>(result_float);
}

